var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"수 년전","JPN":"数年前","ENG":"Years ago","TWN":"數年前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 외각지역, 구 런던\\n<color=#ffd34c>로열 오페라 하우스</color>","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>郊外、旧ロンドン\\n<color=#ffd34c>ロイヤルオペラハウス</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color> Outskirts, Old London\\n<color=#ffd34c>Royal Opera House</color>","TWN":"管理局直轄城<color=#ffd34c>查雷德</color>外圍地區，舊倫敦\\n<color=#ffd34c>皇家歌劇院</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"설명하도록, 오지만디아스.","JPN":"オジマンディアス、説明しろ。","ENG":"Care to explain yourself, Ozymandias?","TWN":"好好跟我說明，奧茲曼迪亞斯。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"설마 나를 속인 건가? 분명 일생일대의 중요한 문제라고 했을 텐데?","JPN":"私を騙したのか？　一生に一度の重大事だと言ったのは君だが。","ENG":"Don't tell me you deceived me. You said this was a once-in-a-lifetime matter.","TWN":"你該不會在耍我吧？你不是說這是攸關一生的大事嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하아, 속이다니? 기껏 불러줬더니 말이 너무 심하네~","JPN":"はあ、騙す？　せっかく呼んであげたのにあんまりだわ～","ENG":"*Sigh* Deceived you? I went out of my way to invite you, and that's how you thank me?","TWN":"哈啊，耍你？我好不容易把你請來，說話也太難聽了吧～"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이래서 예술적 안목이 없는 인간은 상대하기 피곤하다니까.","JPN":"これだから芸術的センスのない人間と話すのって疲れるのよね。","ENG":"This is why people with no artistic sensibility are such a chore to deal with.","TWN":"所以才會說，和沒有藝術鑑賞力的人相處起來會特別累。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"잘 들으라고, 이 아저씨야.","JPN":"よく聞きなさい。","ENG":"Listen carefully, old man.","TWN":"給我聽好了，大叔。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이곳 오페라 하우스의 VVIP 티켓은 엔간해서는 돈 주고도 못 구해.","JPN":"このオペラハウスのVVIPチケットは、単にお金が多いだけじゃ手に入らないのよ。","ENG":"VVIP tickets to this opera house are practically impossible to get, even with money.","TWN":"這座歌劇院的VVIP門票，不是有錢就能買到。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"같은 가격, 같은 좌석으로 예약하면, 3년 뒤에나 관람할 수 있단 말이야.","JPN":"今この値段でこの座席を予約しても、観劇できるのは3年後とかなの。","ENG":"Same price, same seats? You'd be waiting three years before you ever got in.","TWN":"如果要預約同樣價格、同樣的座位，要等3年後才看得到。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이 종이 쪼가리 한 장이 블랙 네트워크에서 얼마에 팔리는지 알기나 해?","JPN":"ブラックネットワークでこの紙切れ1枚がいくらで取引されているか、知ってる？","ENG":"Do you have any idea how much this scrap of paper goes for on the Dark Network?","TWN":"你知道這一張紙在暗網能賣多少錢嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그래서? 그게 나랑 무슨 상관이지?","JPN":"だから何だ？　私と何の関係がある。","ENG":"So what? What does that have to do with me?","TWN":"所以呢？那跟我有什麼關係？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"무슨 상관이냐고? 당연히 상관있지!","JPN":"何の関係がある？　そりゃーあるでしょう！","ENG":"What do you mean, what does it have to do with you? Of course it does!","TWN":"有什麼關係？當然有啊！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"바로 이 오지만디아스님께서 그 VVIP 티켓을 손에 넣었다는 말씀!","JPN":"このオジマンディアス様が、そのVVIPチケットを手に入れたのよ！","ENG":"Yours truly, Ozymandias, managed to get her hands on those VVIP tickets!","TWN":"因為奧茲曼迪亞斯我，弄到那張VVIP門票了！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그것도 두 장씩이나……!","JPN":"しかも2枚……！","ENG":"Two of them, no less...!","TWN":"而且還是兩張……！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L24_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이런 굉장한 공연을 볼 수 있는 게, 일생일대의 중요한 문제가 아니면 뭐겠어?","JPN":"こんなすごい公演が観れるのなら、一生に一度の重大事にもなるって！","ENG":"If seeing a performance like this isn't a once-in-a-lifetime matter, then what is?","TWN":"能親眼看到這種等級的演出，還不算是攸關一生的大事嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L28_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"후후, 나 같은 공인 카운터가 곁에 있다는 걸 영광으로 알라고?","JPN":"ふふ、身近に私のような公認カウンターがいることを光栄に思いなさいよね。","ENG":"Haha, you should be honored to have an Official Counter like me at your side.","TWN":"呵呵，我這種認證制裁者陪在你身邊，你要感到榮幸吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"영광? 지금 제정신으로 하는 소리인가?","JPN":"光栄？　正気か？","ENG":"Honored? Are you even listening to yourself?","TWN":"榮幸？你現在還清醒嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"으, 으응?","JPN":"う、うん？","ENG":"H-huh...?","TWN":"呃、嗯？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"며칠 전에 발생한 사건으로, 샤레이드 관리국은 현재 비상시국이야.","JPN":"つい先日発生した事件で、シャレード管理局は現在非常事態にある。","ENG":"After the incident a few days ago, the Charade Administration is in a state of emergency.","TWN":"查雷德管理局因為前幾天發生的事件，目前正處於緊急狀態。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 수사 인력은 국제 범죄 조직, <color=#ffd34c>육익</color>의 단서를 쫓기 위해 총동원된 상태지.","JPN":"管理局の捜査員は国際犯罪組織、<color=#ffd34c>六翼</color>の手がかりを追うために総動員されている状態だ。","ENG":"All investigative forces are mobilized to track leads on the international criminal organization, <color=#ffd34c>Six Wings</color>.","TWN":"所有調查人力都在全力追查國際犯罪組織<color=#ffd34c>六翼</color>的線索。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"이런 시국에 시니어가 한가롭게 공연이나 관람하는 게 말이 된다고 생각하나?","JPN":"昨今の状況でシニアがのんびりと公演を観覧するなど、言語道断であろう！","ENG":"And you think it's appropriate for a Senior to sit around watching a performance at a time like this?","TWN":"在這種情況下，你覺得Senior悠哉看表演合理嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"흥! 말이 안 될 건 또 뭔데?","JPN":"ふん！　相っ変わらず堅物なこと。","ENG":"Hmph! And why wouldn't it be?","TWN":"哼！哪裡不合理了？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"지위라는 건 이럴 때 쓰라고 있는 거잖아? 놀 때는 확실히 놀아줘야지!","JPN":"地位ってのはこういう時に使うものじゃない。息抜きはしっかりやらないと！","ENG":"Status exists for moments like this, you know. When you play, you play hard!","TWN":"地位不就是要用在這種時候嗎？玩的時候就該好好玩！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"수사는 아랫것들한테 맡겨 버리면 그만이라고?","JPN":"捜査は部下に任せとけばいいのよ。","ENG":"You can just dump the investigation on your underlings.","TWN":"調查丟給下面的人處理不就好了？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"하아, 말다툼도 이젠 지치는군…….","JPN":"はあ……いつものことだが、君とはまったく話が通じない。","ENG":"*Sigh* Even arguing with you is exhausting now...","TWN":"唉……懶得跟你吵了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"비서관, 복귀하겠다. 차를 준비하도록.","JPN":"秘書官、復帰する。車を用意してくれ。","ENG":"Secretary, have the car prepared. I'm returning.","TWN":"祕書，我要回去，準備車子。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L43_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"자, 잠깐만! 리하르트! 정말로 후회 안 할 자신 있어?","JPN":"ちょっ、待ってよリヒャルト！　本当に後悔しない自信ある？","ENG":"W-wait! Richard! Are you sure you won't regret this?","TWN":"等、等等！理查！你真的不會後悔嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"대정화 전쟁 속에서도 살아남은 로열 오페라 하우스의 라 트라비아타야!","JPN":"大浄化戦争でも生き残ったロイヤルオペラハウスのラ・トラヴィアータなのよ？","ENG":"It's La Traviata! Performed at the Royal Opera House that survived the Grand Purification War!","TWN":"那可是在大淨化戰爭中倖存下來的皇家歌劇院演出的《茶花女》耶！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"틀림없이 일생일대의 공연이 될 거란 말이야! 표 구하느라 얼마나 고생했는데!","JPN":"間違いなく一生に一度しか見られない公演になるわ！　チケット取るのにどれだけ苦労したかわかってるの？","ENG":"I'm telling you, this is guaranteed to be the performance of a lifetime! Do you know how hard it was to get these tickets?","TWN":"那絕對會是一生必看一次的演出啊！我可是費盡千辛萬苦才弄到票的耶！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"글쎄? 잘 모르겠군.","JPN":"さあ、わからないな。","ENG":"Well. I couldn't say.","TWN":"是嗎？我不敢說。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"네놈도 알다시피 나는 예술적 안목이 없는 인간이라서 말이지.","JPN":"君の言う通り、私は芸術的センスを持ち合わせていない人間でな。","ENG":"As you know, I lack any real appreciation for the arts.","TWN":"你也知道，我這個人沒有藝術鑑賞力。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"우이씨……!","JPN":"もう……！","ENG":"Errrgh...!","TWN":"嘖……！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"애초에 보고 싶다면, 네놈 혼자 보면 그만이야. 왜 나를 끌어들이려는 거지?","JPN":"そもそも、公演が見たいのなら一人で行けばいい。なぜ私を巻き込もうとする？","ENG":"If you want to watch it that badly, go alone. Why drag me into this?","TWN":"你想看的話自己來就好，幹嘛非要拉我下水？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"에잇! 마음 같아서는 나도 그러고 싶지! 누가 댁 같이 앞뒤 꽉 막힌 꼰대랑…… ","JPN":"ふん！　こっちだってそうしたいわよ！　誰があなたみたいな堅物男と…… ","ENG":"Oh, come on! As if I wouldn't prefer that! Who'd want to sit with a stiff, close-minded boomer like–","TWN":"可惡！我也不想啊！誰要跟你這種死腦筋老古板…… "},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"헙!?","JPN":"はっ！？","ENG":"Huh?!","TWN":"啊！？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그렇군. 또 내 이름을 팔았나?","JPN":"なるほど。また私の名前を利用したのだな。","ENG":"I see. You used my name again, didn't you?","TWN":"原來如此，你又出賣我的名字了嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"쳇, 하여간 눈치 한번 더럽게 빠르네…….","JPN":"ちっ、勘だけは鋭いんだから……","ENG":"Tch. You really are annoyingly sharp...","TWN":"嘖，反應還是一樣快……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"나도 어쩔 수 없었다고. 여기 극장주가 당신 연설을 꼭 듣고 싶다는데 어떡해?","JPN":"だって仕方なかったのよ。ここのオーナーが、どうしてもあなたの演説を聞きたいって言うから。","ENG":"I didn't have a choice. The theater owner insisted on hearing your speech.","TWN":"我也沒辦法啊，劇院老闆說無論如何都想聽你的演說。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이렇게 좀 부탁할게! 그냥 무대 인사 정도면 충분하다니깐?","JPN":"だからお願い！　ちょっとした舞台挨拶程度でいいから。","ENG":"Just do me this favor! A simple curtain greeting will be enough.","TWN":"拜託啦！只要簡單致詞就好！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"무, 무대 인사……!?","JPN":"ぶ、舞台挨拶……！？","ENG":"A-a curtain greeting...?!","TWN":"致、致詞……！？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"지금 리허설도 없이, 즉석에서 무대에 서라고?","JPN":"リハーサルもなしに、即興で舞台に上がれというのか？","ENG":"You expect me to step on stage without rehearsal, on the spot?","TWN":"沒有彩排，直接上台？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐야, 뭘 그렇게 부끄러워해? 기분 나쁘게.","JPN":"何をそんな恥ずかしがるわけ？　気持ち悪い。","ENG":"Huh? Why are you getting flustered? You're killing the mood.","TWN":"幹嘛這麼害羞？真讓人掃興。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"누가 아저씨 춤이랑 노래 보고 싶대? 평소처럼 훈화 말씀 몇 마디면 된다고.","JPN":"あなたの歌やダンスなんか誰も興味ないわ。いつものような演説を一言二言話してくれればそれで充分。","ENG":"Nobody's asking you to sing or dance. Just give one of your usual lectures.","TWN":"誰會想看大叔唱歌跳舞啊？只要像平常訓話那樣講幾句就可以了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아니면, 샤레이드 시니어는 대본 없이는 한마디도 못하는 거야?","JPN":"もしかして、シャレードのシニアは台本なしでは一言も喋れないとか？","ENG":"Or what, can Charade's Senior not say a single word without a script?","TWN":"還是查雷德的Senior沒有稿子就一句話也說不出來？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"시끄럽다, 오지만디아스!","JPN":"黙れ、オジマンディアス！","ENG":"Enough, Ozymandias!","TWN":"閉嘴，奧茲曼迪亞斯！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L19_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"네놈은 평생토록 이해하지 못하겠지만, 지위라는 건 늘 책임이 따르는 법이야.","JPN":"君には一生わからんだろうが、地位というものには、常にそれ相応の責任が伴われる。","ENG":"You'll never understand this, but status always comes with responsibility.","TWN":"雖然你這輩子都不會懂，但地位永遠代表責任。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"하물며 이런 사적인 자리에서 내 지위를 들먹일 생각은 추호도 없어.","JPN":"ましてやこのようなプライベートの席で自分の地位を利用するつもりなど毛頭ない。","ENG":"Even here, I have no intention of flaunting my position for personal matters.","TWN":"更別說在這種私人場合，我不可能動用我的身分。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"예이~ 예이~ 그러시겠죠.","JPN":"はいはい、そうでしょうとも。","ENG":"Yeah, yeah. Of course you wouldn't.","TWN":"是是是～你說得都對。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그런데 이걸 어쩌나? 아무래도 시간이 된 모양이거든?","JPN":"でも残念。もう時間になっちゃったわ。","ENG":"But what a shame. Looks like it's time already.","TWN":"不過怎麼辦呢？時間好像到了耶？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"시간……?","JPN":"時間……？","ENG":"Time...?","TWN":"時間……？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAFF_CHARADE_NPC_NULL","text":{"KOREA":"저… 베르너 시니어 님……?","JPN":"あの……シニア・ベルナー……？","ENG":"Um... Senior Werner...?","TWN":"那個……韋爾納Senior……？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"STAFF_CHARADE_NPC_NULL","text":{"KOREA":"스태프 전원 축사 준비를 마쳤습니다. 관객들이 기다리고 계십니다만…….","JPN":"スタッフ全員、シニアをお迎えする準備を整えました。観客の皆さんがお待ちですが……","ENG":"All staff have completed preparations for the address. The audience is waiting...","TWN":"全體工作人員已經準備好致詞流程，觀眾正在等候……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"큭, 외통수인가… 벌써부터 골치가 아파오는군.","JPN":"くっ、まさか手遅れとは……先が思いやられるが……ふう。","ENG":"Kgh. Backed into a corner already... I can feel the headache coming on.","TWN":"嘖，真是進退兩難……我的頭開始痛了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"금방 가겠네. 준비해주게.","JPN":"すぐに行く、手はずを頼む。","ENG":"I'll be there shortly. Make the preparations.","TWN":"我馬上過去，準備吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"큭큭. 거 봐, 결국 할 거면서 괜히 튕기긴~","JPN":"くくっ、ほら。結局やるくせに勿体ぶっちゃって～","ENG":"Hehe. See? You were going to do it anyway. Playing hard to get for nothing.","TWN":"嘿嘿，你看吧，最後還不是要上台～"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"딱 1시간뿐이다. 네놈의 방종에 대한 내 책임감은 말이지.","JPN":"1時間。君の身勝手な行動により背負わされた私の責任の範囲だ。","ENG":"One hour. That's the extent of my responsibility for your excesses.","TWN":"我為你胡做非為負責的極限只有1個小時。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"쩨쩨하긴. 기왕 쓰는 김에 더 쓰지? 1시간짜리 오페라가 어딨다고.","JPN":"けちね。どうせ時間を使うんだからもう少しサービスしたらどう？　オペラが1時間で終わるわけないじゃない。","ENG":"How stingy. Why not just enjoy it since you're already here? Plus, what kind of opera lasts only an hour?","TWN":"真小氣，既然都要靠關係了，乾脆多利用一點啊？哪有1小時的歌劇啦～"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아무튼 자리 맡아 놓을 테니까, 연설이나 잘 하고 오셔~","JPN":"とにかく、先に席に行ってるから演説頑張ってね～","ENG":"Anyway, I'll save us seats. Go give your speech!","TWN":"總之我先去佔位子了，你好好演講吧～"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하아, 이제 됐지?","JPN":"はあ、これでいい？","ENG":"Whew. That should do it, right?","TWN":"這樣可以了吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"MASTER_CHARADE_NPC_NULL","text":{"KOREA":"물론입니다. 오지만디아스 님.","JPN":"もちろんです、オジマンディアス様。","ENG":"Of course, Miss Ozymandias.","TWN":"當然可以，奧茲曼迪亞斯。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하여간 아저씨도 참 취향 별난 사람이네.","JPN":"あなたも変わった人ね。","ENG":"Really, you have the strangest tastes, old man.","TWN":"不過話說回來，那位大叔的品味還真怪。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASTER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"저 꼰대 잔소리가 뭐가 좋다고 이 난리람? 나는 지긋지긋할 지경이라고~","JPN":"あの堅物男の小言が聞きたいだなんて理解できないわ。私はもううーんっざり。","ENG":"What's so great about listening to that boomer lecture? I'm sick of it myself.","TWN":"那種老古板的嘮叨哪裡好了？我都快煩死了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이런 건, 전혀 엔터테인먼트 하지 않잖아?","JPN":"大体こういうの、全然エンターテインメントじゃなくない？","ENG":"This kind of thing isn't entertainment at all.","TWN":"一點娛樂性都沒有啊？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MASTER_CHARADE_NPC_NULL","text":{"KOREA":"후후, 그게 꼭 그렇지만도 않습니다.","JPN":"ふふ、そうでもありません。","ENG":"Haha. I wouldn't say that.","TWN":"呵呵，那倒也不盡然。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MASTER_CHARADE_NPC_NULL","text":{"KOREA":"시니어님께서는 국제 연합군 시절부터 이 도시를 위해, 헌신을 바치던 분이시니까요.","JPN":"シニア様は国際連合軍の頃からこの都市に貢献してくださった方ですから。","ENG":"The Senior has devoted himself to this city since his days in the Multinational Coalition Force.","TWN":"那位Senior自國際聯軍時代起，就為這座城市奉獻至今。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MASTER_CHARADE_NPC_NULL","text":{"KOREA":"저분의 청렴결백한 이미지를, 대중들도 꽤 좋아하거든요.","JPN":"あの方の清廉潔白なイメージは、大衆にも大変好評なのです。","ENG":"The public is quite fond of his image of integrity and incorruptibility.","TWN":"大眾其實很喜歡他清廉正直的形象。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MASTER_CHARADE_NPC_NULL","text":{"KOREA":"대중이 원하는 것을 제공한다. 그것이야말로 엔터테인먼트의 본질이겠죠.","JPN":"大衆の望むものを提供する。それこそエンターテインメントの本質でしょう。","ENG":"Giving the people what they want. That, in essence, is entertainment.","TWN":"提供大眾想要的東西，才是娛樂的本質。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASTER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"흥, 청렴결백은 개뿔이. 그냥 성격 지랄맞은 거지.","JPN":"ふん、清廉潔白じゃなくて、単に融通がきかないだけでしょ。","ENG":"Hmph. Integrity, my foot. He's just got a rotten personality.","TWN":"哼，清廉個鬼，他只是脾氣差而已。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASTER_CHARADE_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어쨌든 고마워. 덕분에 좋아하는 오페라를 공짜로 보게 생겼네.","JPN":"とにかくありがと。おかげで好きなオペラをただで見られて嬉しいわ。","ENG":"Either way, thanks. I get to watch my favorite opera for free.","TWN":"總之謝謝你啦，托你的福我才能免費看喜歡的歌劇。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L6_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"나중에 연락해, 아저씨. 밥 한 번 살 테니까!","JPN":"あとで連絡して。食事でも奢るから！","ENG":"Let's talk later, old man. I'll treat you to a meal sometime!","TWN":"之後聯絡我，大叔。我請你吃飯！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MASTER_CHARADE_NPC_NULL","text":{"KOREA":"영광입니다. 부디 즐거운 관람 되시길.","JPN":"光栄です。ではごゆっくりどうぞ。","ENG":"The honor is mine. I hope you enjoy the performance.","TWN":"那是我的榮幸，祝您觀賞愉快。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MASTER_CHARADE_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASTER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"예상대로. 첫번째 단계는 무난하게 클리어.","JPN":"予想通り、第1ステップは難なくクリア。","ENG":"As expected. The first phase cleared without issue.","TWN":"一如預期，順利通過第一階段。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"역시 빈틈이 없는 리하르트 쪽보다 오지만디아스 쪽을 공략하는 게 정답이었어.","JPN":"やはり、隙のないリヒャルトよりはオジマンディアスを攻略して正解だった。","ENG":"Targeting Ozymandias rather than the flawless Richard was the correct choice.","TWN":"比起毫無漏洞的理查，果然從奧茲曼迪亞斯下手才是對的。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그럼, 이제 다음 단계는…….","JPN":"では、次のステップは……","ENG":"Then, on to the next phase...","TWN":"那麼下個階段……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"subtitle","speaker":null,"text":{"KOREA":"1시간 뒤","JPN":"1時間後","ENG":"One hour later","TWN":"1小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ACTOR_CHARADE_NPC_MALE","text":{"KOREA":"마시자, 마시자. 넘치는 축배 속에 고운 꽃 피어나네.","JPN":"酒を酌み交わそう　祝杯に美しい花が咲き誇る","ENG":"Drink, drink. Let fair blossoms bloom within these overflowing toasts.","TWN":"喝吧，舉起歡樂的酒杯，讓杯中綻放美好。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_CHARADE_NPC_MALE","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"ACTOR_CHARADE_NPC_MALE","text":{"KOREA":"덧없이 흘러가는 시간, 환락으로 취하도록.","JPN":"儚く流れる時間　歓楽に酔いしれるように","ENG":"Let fleeting time slip away, until we are drunk on delight.","TWN":"讓稍縱即逝的時光，盡情沉醉。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_CHARADE_NPC_MALE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ACTOR_CHARADE_NPC_MALE","text":{"KOREA":"사랑의 잔, 달콤한 전율 속에서 이 잔을 마셔 보세.","JPN":"愛の杯　甘い戦慄の中で酌み交わそう","ENG":"From love's cup, within sweet tremors, let us drink this glass.","TWN":"讓我們敬因為愛，而產生的甜蜜悸動。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_CHARADE_NPC_MALE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ACTOR_CHARADE_NPC_MALE","text":{"KOREA":"그녀의 시선이 내 마음을 완전히 사로잡네.","JPN":"彼女の眼差しが心を捉えて離さない","ENG":"Her gaze seizes my heart completely.","TWN":"敬眼前的美麗，已經打動你我的心。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_CHARADE_NPC_MALE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어때, 리하르트? 생각보다 나쁘지 않지?","JPN":"どう、リヒャルト？　案外悪くないでしょ？","ENG":"So, Richard? Not as bad as you expected, right?","TWN":"怎麼樣，理查？沒有你想像中那麼差吧？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"예술에는 아우라라는 게 있거든. 특히 오페라는 현장감이 느껴져서 좋다니까.","JPN":"芸術にはオーラってものがあるのよ。特にオペラは臨場感が伝わってきていいのよね。","ENG":"Art has an aura to it, you know. Opera especially. You can really feel it live.","TWN":"藝術是有氣場的，尤其歌劇的臨場感最棒了。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"오페라에 대해서는 잘은 모르지만…….","JPN":"オペラには詳しくないが……","ENG":"I don't know much about opera, but...","TWN":"雖然我不太懂歌劇……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그렇군. 확실히 나쁘지 않아.","JPN":"そうだな。確かに、悪くはない。","ENG":"I see. It really isn't bad.","TWN":"但的確不壞。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"후후, 그렇지? 이제 나한테 감사한 마음이 생겼으려나?","JPN":"ふふ、でしょう？　これで少しは私に感謝する気持ちになれたかしら？","ENG":"Hehe, right? Starting to feel a little grateful to me now?","TWN":"呵呵，是吧？現在有沒有覺得感謝我了啊？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"으음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"오지만디아스 님. 긴급 상황입니다.","JPN":"オジマンディアス様、緊急事態です。","ENG":"Miss Ozymandias. This is an emergency.","TWN":"奧茲曼迪亞斯，緊急狀況。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L35_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"현재 금융지구 C-24 구역에 CSE. LV2 침식지대가 형성…….","JPN":"現在、金融地区C-24区域にCSEレベル2の侵食地帯が形成……","ENG":"A CSE Lv. 2 Corrupted Area has formed in Financial District C-24...","TWN":"金融區C-24區域形成CSE．LV2侵蝕地帶……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"담당 태스크포스의 출동이 접수되었습니다.","JPN":"担当タスクフォースの出動要請がありました。","ENG":"Deployment orders for the assigned TASKFORCE have been issued.","TWN":"負責的特遣勢力已出動。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하아, 또 일인가?","JPN":"はあ、また仕事？","ENG":"*Sigh* Work again?","TWN":"唉，又有工作？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하여간 공인 카운터는 쉴 틈이 없다니깐?","JPN":"まったく公認カウンターは休む暇もないんだから。","ENG":"Being an Official Counter really doesn't give you a moment's rest.","TWN":"認證制裁者還真是沒空休息耶？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"나도 이쯤에서 일어나지.","JPN":"私もそろそろ帰るとしよう。","ENG":"I suppose I should get up as well.","TWN":"我也該走了。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐야, 초짜처럼 왜 그래?","JPN":"何よ、素人みたいに。","ENG":"What's with you? Why are you acting like a rookie?","TWN":"幹嘛跟新人一樣啊？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"금방 끝나니까 그냥 앉아 있어. 티켓 아깝다고.","JPN":"すぐ終わるから座ってなさい。チケットがもったいないわ。","ENG":"It'll be over quickly. Just sit tight. Or it'll be a waste of a ticket.","TWN":"很快就會結束，你坐著就好。不要浪費票。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"훗, 의외로군. 그 오지만디아스가 뭔가를 아깝다고 생각할 줄이야.","JPN":"ふっ、意外だな。あのオジマンディアスが何かをもったいないと思うとは。","ENG":"Heh. That's unexpected. Didn't think Ozymandias would ever call something a waste.","TWN":"呵，真意外，奧茲曼迪亞斯居然也會覺得可惜。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"말했잖아, 꼰대. 이거 진짜 구하기 힘들었거든?","JPN":"言ったじゃない。チケット取るの苦労したって。","ENG":"I told you, boomer. These were really hard to get.","TWN":"我不是說了嗎，老古板？這票真的很難到手。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"ACTOR_CHARADE_NPC_FEMALE","text":{"KOREA":"나의 즐거운 시간, 전부 그대들과 나눠요.","JPN":"私の楽しい時間　すべて皆様と分かち合います","ENG":"My joyful hours, I share them all with you.","TWN":"只有和你們一起我才知道，要愉快地度過每一分鐘。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ACTOR_CHARADE_NPC_FEMALE","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ACTOR_CHARADE_NPC_FEMALE","text":{"KOREA":"이 세상 모든 것은 헛된 것. 쾌락 없이 모든 것에는 허무만이 남을 뿐.","JPN":"この世で快楽でないものはすべて儚いものなのです","ENG":"All things in this world are vain. Without pleasure, only emptiness remains.","TWN":"世上的一切都很荒唐。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ACTOR_CHARADE_NPC_FEMALE","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ACTOR_CHARADE_NPC_FEMALE","text":{"KOREA":"즐깁시다. 금방 오고 가는 것이 사랑의 기쁨.","JPN":"楽しみましょう　愛の喜びは束の間","ENG":"Let us enjoy it. Love's rapture comes and goes in an instant.","TWN":"所以及時行樂吧，愛的歡樂稍縱即逝。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ACTOR_CHARADE_NPC_FEMALE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ACTOR_CHARADE_NPC_FEMALE","text":{"KOREA":"그것은 피고 지는 꽃, 두 번 다시 즐길 수 없지요.","JPN":"それは咲いては枯れる花　二度と楽しむことはできないのだから","ENG":"A flower that blooms and withers, never to be enjoyed again.","TWN":"如花綻放乃至凋謝，想多一刻都不行。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ACTOR_CHARADE_NPC_FEMALE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"으음, 생각보다 일찍 돌아왔군.","JPN":"うむ、予想よりも早い帰りではないか。","ENG":"Hmm. You're back earlier than I expected.","TWN":"嗯，比我預期還早回來呢。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L9_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"일은 잘 마무리했나, 오지만디아스?","JPN":"無事に済ませてきたのか？　オジマンディアス。","ENG":"Did things wrap up smoothly, Ozymandias?","TWN":"事情處理完了嗎，奧茲曼迪亞斯？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"애석하게 됐군요.","JPN":"残念でしたね。","ENG":"That's unfortunate.","TWN":"真遺憾。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"저는 당신이 기다리던 사람이 아닙니다.","JPN":"私はあなたが待っていた人物ではありません。","ENG":"I'm not the one you were waiting for.","TWN":"我不是你在等的人。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"……이런.","JPN":"……これは。","ENG":"...Oh.","TWN":"……唉呀。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"죄송합니다. 이거 레이디께 실례를 범했군요.","JPN":"申し訳ありません。レディーに失礼な態度を取ってしまいましたね。","ENG":"My apologies. I seem to have been rude to a lady.","TWN":"抱歉，對女士失禮了。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"아니요, 괜찮습니다. 리하르트 베르너.","JPN":"いいえ、大丈夫です。リヒャルト・ベルナー。","ENG":"No, it is quite all right, Richard Werner.","TWN":"不會，理查．韋爾納。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"축사는 잘 들었습니다. 과연 샤레이드를 관리하는 시니어다운 훌륭한 연설이더군요.","JPN":"祝辞、聞かせてもらいました。さすがはシャレードを管理するシニア。立派な演説でした。","ENG":"I listened to your address. A fine speech, worthy of a Senior who governs Charade.","TWN":"我聽了你的致詞。果然是管理查雷德的Senior，演說很精彩。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"한편으로는 의외였답니다. 설마 이곳에서 시니어의 연설을 듣게 될 줄은 몰랐으니까요.","JPN":"同時に意外でした。まさかここでシニアの演説を聞けるとは思わなかったので。","ENG":"In a way, it surprised me. I never imagined I'd hear your speech here of all places.","TWN":"不過我也很意外，沒想到會在這裡聽到你的致詞。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"오페라라니… 군인답지 않은 우아한 취미라고 생각해요.","JPN":"オペラ……軍人だった方には、あまり馴染みのない趣味かと思っていましだが。","ENG":"Opera... I suppose it's an elegant pastime. Not exactly what I'd expect from a soldier.","TWN":"歌劇……我認為是與軍人不相稱的優雅嗜好呢。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 취미라고 하기엔 오늘이 처음입니다.","JPN":"まあ、趣味と言っても今日が初めてでして。","ENG":"Well, I can hardly call it a pastime. Today was my first time.","TWN":"說、說是嗜好，今天其實是我第一次觀賞歌劇。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"무대에 서게 된 것도… 약간의 해프닝이었다고 할 수 있죠.","JPN":"舞台に上がったのも……ちょっとしたハプニングがありまして。","ENG":"And stepping onto the stage... That, too, was something of an incident.","TWN":"站上舞台……只能說是一場小插曲。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"해프닝이라… 글쎄요, 과연 그럴까요?","JPN":"ハプニング……さあ、本当にそうでしょうか？","ENG":"An incident...? Well, was it really?","TWN":"插曲啊……真的是那樣嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"음? 그게 무슨……?","JPN":"うむ？　それはどういう…？","ENG":"Hmm? What do you mean by that...?","TWN":"嗯？這是什麼意思……？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"라 트라비아타는 여주인공 비올레타의 비극적 사랑을 다룬 이야기죠.","JPN":"ラ・トラヴィアータはヒロイン「ヴィオレッタ」の悲劇的な恋をテーマにした物語です。","ENG":"La Traviata is a story of the tragic love of its heroine, Violetta.","TWN":"《茶花女》描寫的是女主角薇奧蕾塔悲劇般的愛情故事。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"프랑스 파리 사교계의 꽃이었던 비올레타가 한 남성과 사랑에 빠지게 되지만…….","JPN":"フランス、パリの社交界の花であったヴィオレッタは一人の男性と恋に落ち……","ENG":"Once the flower of the Parisian socialite, she falls in love with a man...","TWN":"她曾是巴黎社交界的交際花，卻愛上了一名男子……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"이내, 그들은 여러 문제와 직면하고 말아요.","JPN":"あらゆる問題に直面します。","ENG":"But soon, they are faced with many obstacles.","TWN":"之後，兩人面臨重重難關。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"신분의 차이, 사회적인 통념, 경제적 사정 그리고 가족 관계…….","JPN":"身分の差、社会的常識、経済的な事情、そして家族関係……","ENG":"Differences in status, social conventions, finances, and family ties...","TWN":"身分差距、社會成見、經濟狀況與家庭關係……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"결과적으로 비올레타는 사랑하는 사람과 이어지지 못하고, 평생을 방황하다 죽게 되죠.","JPN":"結局ヴィオレッタは想い人と結ばれず、彷徨い続けて生涯を終える。","ENG":"In the end, Violetta cannot be with the one she loves, and dies after a life of wandering.","TWN":"最終，薇奧蕾塔無法與愛人結合，漂泊一生至死。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그것이 라 트라비아타의 결말이랍니다.","JPN":"それがラ・トラヴィアータの結末です。","ENG":"That is the ending of La Traviata.","TWN":"那便是《茶花女》的結局。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"라 트라비아타…….","JPN":"ラ・トラヴィアータ……","ENG":"La Traviata...","TWN":"《茶花女》……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그래서 <color=#ffd34c>방황하는 여인</color>이로군요.","JPN":"それで<color=#ffd34c>道を踏み外した女</color>ですか。","ENG":"So it means <color=#ffd34c>The Wandering Woman</color>.","TWN":"所以才被稱為<color=#ffd34c>迷途的女人</color>啊。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"맞아요, 제가 이 오페라를 처음 관람한 건 아주 어릴 적이었답니다.","JPN":"そうです。私が最初にこのオペラを観たのは、まだ本当に幼い時でした。","ENG":"Yes. I first saw this opera when I was very young.","TWN":"對。我第一次觀賞這部歌劇時，年紀還很小。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"제 조부님의 말씀에 따르면, 라 트라비아타의 초연은 그다지 성공적이지 못했다고 해요.","JPN":"祖父の話によると、ラ・トラヴィアータの初演の反応はあまりよくなかったそうです。","ENG":"According to my grandfather, its premiere was not particularly successful.","TWN":"據我祖父所說，這部作品首演時其實並不成功。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"오페라를 만든 베르디의 사상이 시대를 뛰어넘어 너무 앞서갔기 때문이라고 하셨죠.","JPN":"オペラを作ったヴェルディの思想が前衛的すぎたせいだと。","ENG":"He said it was because Verdi's ideas were far ahead of their time.","TWN":"因為作者威爾第的思想過於超前。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"하지만 조부의 손을 붙잡고, 밀라노 라 스퀼라의 무대에서 비올레타를 보게 되었을 때.","JPN":"ですが、祖父の手を握りミラノのスカラ座の舞台でヴィオレッタを観たあの時。","ENG":"But when I held his hand and watched Violetta on the stage of La Scala in Milan...","TWN":"但當我牽著祖父的手，在米蘭斯卡拉大劇院看到薇奧蕾塔時，"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"저는 문득 그녀처럼 되고 싶다고 생각했어요.","JPN":"私はふと、彼女のようになりたいと思ったのです。","ENG":"I suddenly found myself wanting to become like her.","TWN":"我突然希望，自己能成為她。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그 춤과 노래가 너무나 우아해서…….","JPN":"その踊りと歌があまりにも優雅で……","ENG":"Her dance and song were so elegant...","TWN":"那舞姿與歌聲，是如此優雅……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그녀의 최후가 비극으로 끝난다는 건, 처음부터 알고 있었는데도…….","JPN":"彼女の人生が悲劇で終わると、最初から知っていたにもかかわらず……","ENG":"Even though I knew from the start that her end would be tragic...","TWN":"即使一開始就知道，她的結局是悲劇……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ACTOR_CHARADE_NPC_FEMALE","text":{"KOREA":"산다는 게 꼭 불 속 같네요.","JPN":"人生はまるで炎の中ですね","ENG":"Living feels like standing in a fire.","TWN":"活著，就像置身火焰中。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_CHARADE_NPC_MALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_CHARADE_NPC_FEMALE","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ACTOR_CHARADE_NPC_MALE","text":{"KOREA":"아직 사랑을 모를 때는 그렇겠지.","JPN":"まだ愛を知らないうちは","ENG":"Perhaps so, before one has ever known love.","TWN":"在尚未知愛為何物前，或許是如此。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_CHARADE_NPC_MALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_CHARADE_NPC_FEMALE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ACTOR_CHARADE_NPC_FEMALE","text":{"KOREA":"저는 잘 모르겠어요.","JPN":"私にはよくわかりません","ENG":"I don't really know.","TWN":"我不太明白。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_CHARADE_NPC_MALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_CHARADE_NPC_FEMALE","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ACTOR_CHARADE_NPC_MALE","text":{"KOREA":"그러나 그것이 내 운명이오.","JPN":"しかしそれが僕の運命なのだ","ENG":"But that is my destiny.","TWN":"但那就是我的命運。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_CHARADE_NPC_MALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ACTOR_CHARADE_NPC_FEMALE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"축배의 노래…….","JPN":"祝杯の歌……","ENG":"Brindisi...","TWN":"飲酒歌……"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_CHARADE_NPC_MALE","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":{"char_id":"ACTOR_CHARADE_NPC_FEMALE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"당대의 실력에는 못 미치지만, 현대 프리마돈나의 소프라노도 썩 나쁘진 않네요.","JPN":"当時のパフォーマンスには及びませんが、現代のプリマドンナのソプラノも悪くありませんね。","ENG":"It may not match the mastery of its era, but the modern prima donna's soprano isn't bad at all.","TWN":"雖然不及當年的水準，但現代首席女高音也相當不錯。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_CHARADE_NPC_MALE","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":{"char_id":"ACTOR_CHARADE_NPC_FEMALE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"틀림없이 이곳 무대에 오르기 위해서, 필사적으로 발버둥 친 결과겠죠.","JPN":"きっとこの舞台に立つために、必死に足掻いた結果でしょう。","ENG":"No doubt the result of her desperate struggle to reach this stage.","TWN":"為了站上這個舞台，她一定也拼命掙扎過吧。"},"stage":{"bg":"HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ACTOR_CHARADE_NPC_MALE","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":{"char_id":"ACTOR_CHARADE_NPC_FEMALE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"1885년 밀라노 극장에서 첫 데뷔 무대로 라 트라비아타를 노래했던 저처럼…….","JPN":"1885年、ミラノの劇場でラ・トラヴィアータを歌った私のように……","ENG":"Just like when I sang La Traviata as my debut performance in a Milan theater in 1885...","TWN":"就像1885年在米蘭劇院，以《茶花女》作為出道舞台的我一樣……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"1885년……?","JPN":"1885年……？","ENG":"1885...?","TWN":"1885年……？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 설마……!?","JPN":"待て、まさか……！？","ENG":"Wait. Don't tell me...?!","TWN":"等等，難道……！？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くっ……！","ENG":"Ghk...!","TWN":"唔……！"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"눈치가 빠르시네요, 리하르트 베르너.","JPN":"察しがいいですね、リヒャルト・ベルナー。","ENG":"You're quite perceptive, Richard Werner.","TWN":"你反應很快呢，理查．韋爾納。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"하지만 오지만디아스는 늦을 거예요. 그렇게 각본을 짜두었거든요.","JPN":"言っておきますが、オジマンディアスなら遅れますよ。そうなるように脚本を組み立てておいたので。","ENG":"But Ozymandias will be late. I made sure the script played out that way.","TWN":"不過奧茲曼迪亞斯會晚到，我已經安排好了。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"이게 무슨 짓이지? 각본이라고?","JPN":"何のつもりだ？　脚本だと？","ENG":"What is this supposed to be? A script?","TWN":"這是什麼意思？安排？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"걱정마세요, 오늘 밤 제 각본에서 당신을 해치는 전개는 상정해 두지 않았습니다.","JPN":"心配要りません。私の脚本上、今夜あなたに被害が及ぶ展開は想定されていません。","ENG":"Don't worry. In tonight's script, I never planned for you to be harmed.","TWN":"放心吧。今晚的劇本裡，並沒有要傷害你的橋段。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그렇군…….","JPN":"私の勘違いでなければ……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"너는 다른 세계로부터의 이방인… <color=#ffd34c>엑자일러</color>인가?","JPN":"君は異世界から来た異邦人……<color=#ffd34c>エグザイラー</color>なのか？","ENG":"You're an outsider from another world... an <color=#ffd34c>Exile</color>?","TWN":"你是來自其他世界的異鄉人……<color=#ffd34c>流放者</color>嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"맞아요. 제 고향 세계는 이미 오래전에 이면세계가 되어버렸죠.","JPN":"ええ。私の故郷の世界は遠い昔、裏世界になってしまいました。","ENG":"That's right. My home world became the Counterside long ago.","TWN":"沒錯。我故鄉所處的那個世界，早已化為異界。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그리고 제가 있던 런던에도 이곳처럼 로열 오페라 하우스가 있었답니다.","JPN":"そして私がいたロンドンにもここと同じく、ロイヤルオペラハウスがあったのです。","ENG":"And in the London I knew, there was a Royal Opera House just like this one.","TWN":"而我所在的倫敦，也曾有一座皇家歌劇院。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"이것 참 감회가 새롭다고 해야 할까요?","JPN":"感慨深いとでも言うべきでしょうか。","ENG":"Should I call it nostalgia?","TWN":"這該說是真是令人感慨萬千？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"이 세계에서 있었던 1999년의 보수 공사 때문에 극장의 모습은 달라진 모양이지만.","JPN":"この世界では1999年に補修工事が行われ、今や外見こそ少々違いますが。","ENG":"The theater's appearance seems to have changed after the renovations in 1999 in this world, but...","TWN":"雖然這個世界在1999年整修過，似乎改變了劇院外觀，"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"기본적인 건물의 구조는 제 기억 속 풍경과 달라지지 않았어요.","JPN":"建物の基本的な構造は私の記憶の中にあるものと一緒です。","ENG":"The basic structure remains the same as in my memories.","TWN":"但基本結構仍與我記憶中的風景一致。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"의장실과 대기실, 객석과 무대의 배치 구조 그리고 상연하는 오페라까지…….","JPN":"衣装室と控え室、客席や舞台の配置、構造、そして上演するオペラの演目まで……","ENG":"The director's office, the waiting rooms, the seating, the stage layout, even the opera being performed...","TWN":"議事廳、後台、觀眾席與舞台的配置，甚至上演的歌劇……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그리운 노스텔지어. 그래서 당신에게는 나름대로 감사하고 있답니다.","JPN":"懐かしきノスタルジア。だからあなたにはそれなりに感謝しています。","ENG":"A fond nostalgia. That's why I'm grateful to you, in my own way.","TWN":"真令人懷念，所以我對你心存感激。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"대정화 전쟁에서 당신이 이끌던 국제 연합군이 이곳을 지켜내지 못했다면.","JPN":"大浄化戦争であなたが率いた国際連合軍がここを守りきれていなかったら……","ENG":"If the Multinational Coalition Forces you once led had failed to protect this place during the Grand Purification War...","TWN":"若非你在大淨化戰爭中率領的國際聯軍守住了這裡，"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"이 극장 또한, 여느 멸망한 세계들처럼 역사의 뒤안길로 사라져 버리고 말았겠죠.","JPN":"この劇場も、これまで滅び去った幾多の世界のように、歴史の裏へと消えてしまっていたでしょう。","ENG":"This theater, like so many ruined worlds, would have vanished into the shadows of history.","TWN":"這座劇院恐怕也會像其他滅亡的世界被歷史掩埋。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"아까부터 영문을 알 수 없는 소리를 지껄이는군.","JPN":"先程から訳のわからないことを。","ENG":"You've been rambling nonsense for a while now.","TWN":"從剛才開始，你就一直說些莫名其妙的話。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"하고 싶은 말이 뭐지? 날 해칠 생각이 없다면, 이방인이 내게 무슨 볼일인가?","JPN":"何が言いたい？　危害を加えるつもりがないなら、異邦人が私に何の用がある？","ENG":"What is it you want? If you don't intend to harm me, what business does an outsider have with me?","TWN":"你到底想說什麼？若不是來害我，找我有什麼目的？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"이해해요. 원래부터 이 세계 주민인 당신 입장에는 다소 혼란스러울 수도 있겠군요.","JPN":"わかります。元からこの世界の住人であるあなたからすれば、多少混乱してもおかしくありません。","ENG":"I understand. From your perspective, as someone native to this world, it must all seem confusing.","TWN":"我理解，對原本就生活在這個世界的你來說，確實難以消化。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"하지만 제 용건은 심플합니다.","JPN":"私の要件はシンプルです。","ENG":"But my purpose is simple.","TWN":"但我的要求很簡單。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"당신과 거래를 하고 싶어요, 리하르트 베르너.","JPN":"リヒャルト・ベルナー、あなたと取引がしたいのです。","ENG":"I wish to make a deal with you, Richard Werner.","TWN":"我想和你進行一筆交易，理查．韋爾納。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"거래라고?","JPN":"取引だと？","ENG":"A deal?","TWN":"交易？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그렇습니다. 제가 당신에게 바라는 것은 공신력 있고 확실한 신분…….","JPN":"そうです。私があなたに望むものは、社会的に信用される確実な身分……","ENG":"Yes. What I ask of you is a credible, unquestionable status...","TWN":"對。我希望你能給我一個具有公信力又確實的身分……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그러니 저를 샤레이드 최고의 여배우로 만들어주세요.","JPN":"それをもってして、私をシャレード随一の女優に仕立ててください。","ENG":"So please, make me Charade's greatest actress.","TWN":"把我捧成查雷德最頂尖的女演員。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"배우라고? 무슨 헛소리지?","JPN":"女優？　何を言っている？","ENG":"Actress? What kind of nonsense is that?","TWN":"演員？你在胡說什麼？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드의 엔터테인먼트 사업은 이미 과포화 상태야.","JPN":"シャレードのエンターテインメント事業はすでに飽和状態だ。","ENG":"Charade's entertainment industry is already oversaturated.","TWN":"查雷德的娛樂產業早就飽和了。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"하물며 관리국이 뒤에서 개입한다고 대중의 선택을 받을 수 있는 것도 아니지.","JPN":"管理局が裏で手を引いたところで、大衆に選ばれるという保証もない。","ENG":"Even if the Administration intervenes behind the scenes, it won't guarantee public favor.","TWN":"就算管理局介入，也不代表能獲得大眾青睞。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그런 건 걱정할 필요 없어요. 제게 배우로서의 소질은 차고도 넘칠 만큼 충분하니까요.","JPN":"心配する必要はありません。私には役者として溢れんばかりの才気がありますので。","ENG":"You needn't worry about that. I have more than enough talent as an actress.","TWN":"這點不必擔心，我當演員的資質綽綽有餘。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"당신들은 그저 계기만 제공해주시면 됩니다.","JPN":"あなた方はただ、きっかけを提供するだけで十分です。","ENG":"All you need to provide is the opportunity.","TWN":"你們只需要提供一個契機。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"과정이야 어찌됐든, 결과적으로 대중은 틀림없이 저라는 아이콘을 선호할 테니까요.","JPN":"過程がどうであれ、結果的に大衆は私という存在に惹かれるでしょう。","ENG":"No matter the process, the public will inevitably come to favor me as an icon.","TWN":"無論過程如何，結果大眾一定會喜歡我這個「象徵」。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"아이콘을 선호할 거라고? 그게 무슨 뻔뻔한……?","JPN":"君に惹かれるだと？　おこがましい……","ENG":"They'll favor you as an icon? How brazen can you be...?","TWN":"喜歡你？真是厚臉皮……？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"단지, 저는 그 시간을 단축하고 싶을 뿐이랍니다.","JPN":"私はそこにかかる時間を短縮したいだけです。","ENG":"I merely wish to shorten the time it takes.","TWN":"我只是想縮短那段時間而已。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"아시다시피, 샤레이드에서 부와 명성은 쓰다 버릴 수단에 불과하니까.","JPN":"ご存じの通り、シャレードで富と名声は使い捨ての手段に過ぎませんから。","ENG":"As you know, in Charade, wealth and fame are nothing more than disposable tools.","TWN":"畢竟在查雷德，財富與名聲不過是用完即丟的工具。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"……후우.","JPN":"……ふう。","ENG":"*...Sigh*","TWN":"……呼。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그래서? 거래라면, 이쪽에도 이득이 되는 조건을 준비해 두었겠지?","JPN":"それで？　取引というからには、こちらの得になる条件を用意しているんだろうな。","ENG":"So? If this is a deal, you must have prepared terms that benefit me as well.","TWN":"所以呢？既然是交易，想必你也準備了對我有利的條件？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"물론이죠. 거래가 유지되는 동안, 당신의 그림자가 되어드리겠습니다.","JPN":"もちろんです。取引が有効な間は、あなたの影になってさしあげます。","ENG":"Of course. For as long as the deal stands, I will become your shadow.","TWN":"當然。在交易期間，我會成為你的影子。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"또한 당신이 쫓고 있는 국제 범죄 조직 육익에 관한 첩보를 제공해드리죠.","JPN":"あなたが追っている国際犯罪組織、六翼に関する情報も提供しましょう。","ENG":"And I will provide you with intelligence on the international criminal organization, Six Wings.","TWN":"並提供你正在追查的國際犯罪組織六翼的情報。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 뭐라고…? 방금 육익이라고 했나……?","JPN":"い、今、六翼と言ったか……？","ENG":"W-what...? Did you just say Six Wings...?","TWN":"什、什麼？你剛才說六翼……？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"대체 그 이름은 어디서 들은 거지?","JPN":"その名前をどこから聞いた？","ENG":"Where did you even hear that name?","TWN":"你從哪裡知道那個名字的？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"육익은 관리국이 수년 간 극비로 쫓고 있는 비밀 결사 조직이야.","JPN":"六翼は管理局がこの数年間、極秘で捜査している秘密結社組織だ。","ENG":"Six Wings is a secret cabal the Administration has pursued in absolute secrecy for years.","TWN":"六翼是管理局多年來極機密追查的祕密組織。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"하지만 조직의 규모, 설립 목적과 범행 수법… 그 무엇도 명확히 밝혀내지 못했지.","JPN":"しかし組織の規模、設立目的と犯行手段……何一つ解き明かせてない。","ENG":"Its scale, purpose, methods... none of it has been clearly uncovered.","TWN":"組織的規模、目的、犯罪手法……我們全都不清楚。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"하물며 민간에는 그 이름조차 공개되지 않았어.","JPN":"民間人には名前すら公表されていないんだ。","ENG":"The name itself hasn't even been made public.","TWN":"連名字都未曾對大眾公開。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그런데 느닷없이 나타난 이방인이 육익에 관한 첩보를 넘겨주겠다고?","JPN":"なのに、突然現れた異邦人が取引の材料として六翼の情報を挙げるだと？","ENG":"And now an outsider appears out of nowhere, offering intelligence on Six Wings?","TWN":"如今卻有個突然出現的異鄉人說要提供情報？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"지금 나 보고 그 말을 믿으라는 건가?","JPN":"私がその話を信じると思うか？","ENG":"Are you seriously asking me to believe that?","TWN":"你要我相信這種話？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그건 간단한 이야기랍니다, 리하르트 베르너.","JPN":"簡単な話です、リヒャルト・ベルナー。","ENG":"It's quite a simple matter, Richard Werner.","TWN":"這很簡單，理查．韋爾納。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"육익에 관해서라면, 저는 누구보다도 확실한 정보원을 가지고 있거든요.","JPN":"六翼のことなら、私は誰よりも確実なソースを持っているのです。","ENG":"When it comes to Six Wings, I have a more reliable informant than anyone else.","TWN":"因為關於六翼，我擁有最確實的情報來源。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"확실한 정보원이라고……?","JPN":"確実なソース……？","ENG":"A reliable informant...?","TWN":"情報來源……？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그렇습니다.","JPN":"ええ。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"그 정보원의 출처는 저 자신…….","JPN":"そのソースの出所は、私自身……","ENG":"Because the informant is none other than me...","TWN":"那個來源，就是我自己……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"육익의 일원, 스완 클레어니까요.","JPN":"六翼の一員、スワン・クレアなのですから。","ENG":"A member of Six Wings, Swan Claire.","TWN":"六翼的一員，史旺．克萊爾。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이걸로 이 세계에서 새로운 무대에 오를 준비는 모두 마쳤군.","JPN":"これで、この世界を舞台にする新たな脚本が始まる。","ENG":"All preparations to step onto a new stage in this world are complete.","TWN":"這樣一來，在這個世界登上新舞台的準備就全部完成了。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"멤버들의 행적이 외부로 드러나지 않도록 하라는 건가요?","JPN":"メンバーの動きが外にバレないようにする、ということでしょうか？","ENG":"You want me to keep the members' whereabouts from being revealed to the outside?","TWN":"你不想讓外界看到成員們的行蹤？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"맞아요. 그게 육익에서 당신이 맡게 될 일입니다.","JPN":"そうです。それが六翼で君が務めることになる仕事です。","ENG":"Yes. That will be your role in Six Wings.","TWN":"沒錯，這就是你在六翼中要做的事。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"각본을 꾸미는 당신의 재능에 가장 어울리는 역할이라고 판단했어요.","JPN":"脚本を作りあげる君の才能に最も相応しい役割だと判断しました。","ENG":"I believe it's the perfect role that matches your talents for devising scripts.","TWN":"我們認為這個職責非常適合你的劇本寫作才華。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"타인의 발자국을 지운다는 건 제가 그 발자국의 가장 가까운 곳에 있어야 한다는 뜻이죠.","JPN":"他人の足跡を消すということは、私がその足跡と一番近い場所に居なければならないということですね。","ENG":"Being able to erase another's footprints means that I have to be the closest to those footprints.","TWN":"要消除別人的腳印就表示我必須離他們非常近。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>외부인</color>인 저에게 그런 일을 맡기고 함부로 신뢰하는 건 비밀결사의 리더가 보일 법한 행동은 아니네요.","JPN":"<color=#ffd34c>部外者</color>である私にそのような仕事を任せ、むやみに信頼するとは、秘密組織のリーダーが取るべき行動とは思えませんね。","ENG":"And entrusting an <color=#ffd34c>outsider</color> to do that doesn't seem like something a leader of a secret organization should do.","TWN":"把這樣的任務託付給我這個<color=#ffd34c>外人</color>，似乎不像是一個秘密組織的首領會有的行為。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇기 때문에 이 세계의 많은 정보가 필요한 당신에겐 저의 제안을 거절할 이유가 없겠죠.","JPN":"だからこそ、この世界の情報を多く必要とする君は、僕の提案を断る理由がないはずです。","ENG":"You have no reason to decline this offer since you need all the information you can get about this world.","TWN":"所以，對於需要盡可能多收集這個世界的情報的你來說，沒有理由拒絕我的提議。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신에게도 이곳에서 이루고 싶은 궁극의 목적이 있을 테니까요. 우리 육익은 개인의 목적을 존중하는 편이거든요.","JPN":"君にとってもここで成し遂げたい究極の目的があるはずですから。僕たち六翼は個人の目的を尊重していますよ。","ENG":"I'm sure you have something you wish to achieve here. And Six Wings respects everyone's individual goals.","TWN":"在這裡，你可能也有自己想要實現的終極目標，而我們六翼非常尊重成員的個人目的。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 개인의 목적이… 당신들을 등지게 만드는 빌미가 된다고 하더라도 말인가요?","JPN":"その個人の目的が……あなたたちを裏切ることになるとしてもですか？","ENG":"Even if that goal... could be used as an excuse to turn against you?","TWN":"即使那個人的目的……會讓你與她反目？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"어차피 우리의 이해관계가 합치하는 건, 첫번째 클리포트 게임이 승리로 끝날 때까지입니다.","JPN":"どうせ僕たちの利害関係が一致するのは、最初のクリフォトゲームで勝利するまで、ですから。","ENG":"Our interests will only align until the first Qliphoth Game is won.","TWN":"反正我們的合作關係會持續到在第一次逆卡巴拉遊戲勝利為止。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 이후에도 우리와 함께 할 것인지는 당신의 선택에 맡기겠어요.","JPN":"その後も僕たちと行動を共にするかは、君の選択次第です。","ENG":"Afterwards, it's your choice whether you stay or leave us.","TWN":"至於在那以後要不要和我們一起行動，完全取決於你。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 육익이 가진 최종 목적은 뭐죠?","JPN":"あなたたち六翼の最終目的は何ですか？","ENG":"What's the real purpose of Six Wings?","TWN":"你的六翼的最終目標是什麼？"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"세계평화.","JPN":"世界平和。","ENG":"World peace.","TWN":"世界和平。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"누가 보기에도 악의 축이나 다름없는 일들을 꾸미면서 말인가요?","JPN":"誰が見ても悪の組織のようなことを企んでいるのに、ですか？","ENG":"Even when you all are conspiring to do things that people expect an axis of evil to do?","TWN":"但你們做的明明是壞人才會做的事。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"맞습니다. 그렇기 때문에 스완, 당신이라면 이해할 거예요.","JPN":"そうです。だからこそスワン、君なら理解できるはずです。","ENG":"Correct. That's why I believe you'll understand it, Swan.","TWN":"沒錯，所以我相信你能理解我們，史旺。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그것의 정의를 온전히 지키는 것과, 그 정의를 비틀어서라도 지켜내는 것의 차이를요.","JPN":"正義を正しく守ることと、その正義をねじり曲げてでも守り通すことの違いを。","ENG":"The difference between those who strive to uphold justice in its entirety and those who protect it even if it means twisting the justice.","TWN":"忠實地守護其定義，與即使扭曲其定義也堅持守護之間的區別。"},"stage":{"bg":"CITY_CENTER2","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇군요, 대적자.","JPN":"そうなのですね、敵対者。","ENG":"I see, Antagonist.","TWN":"原來如此，敵對者。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저에게 있어서, 이 각본의 궁극적인 목적은…….","JPN":"私にとってこの脚本の究極の目的は……","ENG":"For me, the ultimate purpose of this script is...","TWN":"對我而言，這份劇本的最終目的……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것을 처음으로 되돌리는 것.","JPN":"すべてを振り出しに戻すこと。","ENG":"To return everything to the very beginning.","TWN":"就是讓一切回到最初。"},"stage":{"bg":"SWANSONG_04","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그것을 위해서라면, 그 어떤 배역이라도 받아들이겠다고 각오했으니까요.","JPN":"そのためなら、どんな配役でも受け入れると、覚悟したのですから。","ENG":"And for that, I resolved myself to accept any role, no matter what it may be.","TWN":"為了達成這一點，我早已做好覺悟。無論是什麼樣的角色，我都會接受。"},"stage":{"bg":"SWANSONG_04","bgm":"THEMA_SIXWING","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything proceeds according to the script.","TWN":"一切，皆依照劇本進行。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 육익이 가진 최종 목적이 이 세계의 평화라고 한다면.","JPN":"あなたの六翼が目指すものがこの世界の平和だとしたら。","ENG":"If the final objective of your Six Wings truly is peace for this world...","TWN":"如果你與你的「六翼」所追求的最終目標，真的是這個世界的和平。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어쩌면 우리가 가는 길은 결국에는 돌고 돌아, 같은 목적지를 향하게 될지도 모릅니다.","JPN":"もしかすると、私たちの進む道は……巡り巡って、同じ終着点に繋がるかもしれません。","ENG":"Then perhaps, after many twists and turns, the path we walk may ultimately lead us to the same destination.","TWN":"或許我們兜兜轉轉，最後仍會走向同一個終點。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"물론, 그 각본이 완성되기 위해서는 기적과 기적이 겹쳐야 가능하겠지만…….","JPN":"もちろん、その脚本が完成するためには、奇跡に奇跡を重ねる必要がありますが……","ENG":"Of course, for that script to be completed, it would require miracles piled upon miracles...","TWN":"當然，若要完成那份劇本，勢必要奇蹟疊加奇蹟才有可能……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"베르디의 라 트라비아타는 초연에 실패하고 말았어요.","JPN":"ヴェルディのラ・トラヴィアータは初演に失敗しました。","ENG":"Verdi's La Traviata failed at its premiere.","TWN":"威爾第的《茶花女》在首演時以失敗告終。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 지금까지 제가 구상했던 수많은 각본들 또한 종국에 실패로 돌아가고 말았죠.","JPN":"そして今まで私が練り上げた数多くの脚本も、最後は失敗してしまった。","ENG":"And the countless scripts I devised until now all ended in failure as well.","TWN":"而我至今構想的無數劇本，也全都迎來了失敗的結局。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 유랑했던 그 어떤 세계에서도 <color=#ffd34c>변수</color> 같은 건 없었어요.","JPN":"私が流浪したどの世界でも、<color=#ffd34c>変数</color>などありませんでした。","ENG":"In every world I wandered through, there were no <color=#ffd34c>variables</color>.","TWN":"在我流浪過的任何一個世界，都不存在所謂的<color=#ffd34c>變數</color>。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#83dcb7>천사</color>는 나타나지 않았어요.","JPN":"<color=#83dcb7>天使</color>は現れませんでした。","ENG":"No <color=#83dcb7>angels</color> ever appeared.","TWN":"<color=#83dcb7>天使</color>，也從未現身。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"But still...","TWN":"但是……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼에도 저는 제가 틀렸다고 생각하지 않아요.","JPN":"それでも私は、自分が間違っているとは思いません。","ENG":"Even so, I do not believe I was wrong.","TWN":"即便如此，我依然不認為自己是錯的。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 말한 대로, 세계를 온전히 지켜내는 것과 그것을 부숴서라도 지켜내는 것은 전혀 다르니까요.","JPN":"あなたが言ったとおり、世界を完全な形で守ることと、それを壊してでも守り通すことはまったく違いますからね。","ENG":"As you said, preserving the world intact and preserving it even if one must break it are entirely different things.","TWN":"正如你所說，「完整地守護世界」與「即使將其摧毀也要守護它」，兩者截然不同。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 당신과 당신의 배후에 있는 자가 원하는 것이 정말로 이 세계의 평화라면…….","JPN":"だからあなたと、あなたの背後にいる者が本当に世界の平和を望んでいるのなら……","ENG":"So if what you and the one behind you truly desire is peace for this world...","TWN":"所以如果你，還有你背後的那個人，真正想要的是這個世界的和平……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"부디 클리포트 게임에서 이겨서, 그것을 증명해 내길 바랄게요.","JPN":"どうかクリフォトゲームに勝ち、それを証明できることを祈ります。","ENG":"Then I hope you win the Qliphoth Game, and prove it.","TWN":"那就請在逆卡巴拉遊戲中獲勝，親自證明給我看吧。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대적자 그리고…….","JPN":"敵対者、そして……","ENG":"Antagonist and...","TWN":"敵對者，還有……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"존 스미스.","JPN":"ジョン・スミス。","ENG":"John Smith.","TWN":"約翰．史密斯。"},"stage":{"bg":"BLACK","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};